SELECT OBJECT_ID , BUSINESS_AREA_CD , BUSINESS_TYPE_CD , DOC_CLASS_CD1 AS objectClassCd1 , DOC_CLASS_CD2 AS objectClassCd2 , PRODUCT_CD , ECN_NO , ECN_INSERT_UID , DOCUMENT_NO AS objectNo , REV_NO , DOCUMENT_NM AS objectNm , ACCOUNT_NM , STATUS_CD , TOTAL_SHEET , PROJECT_CD , PROJECT_NM , distributeTypeCd , STD_GAPP_DT AS stdGappDt , CHANGE_GAPP_DT AS changeGappDt , SECURITY_TYPE_CD , PROTECT_YN , DESCRIPTION , INSERT_DEPT_NM , INSERT_UID , INSERT_DT , UPDATE_DEPT_NM , UPDATE_UID , UPDATE_DT , INTERFACE_DT AS interfaceDt , FILENO , fileViewNm , ORG_FILE_NM , FILE_NM , FILE_PATH_NM , fileSize , 'Y' AS inspectionYn FROM ( SELECT info.* , DENSE_RANK() OVER (PARTITION BY info.DOCUMENT_NO ORDER BY info.DOCUMENT_NO, CASE WHEN LENGTH(info.REV_NO)=1 THEN info.REV_NO||'Z' ELSE REGEXP_REPLACE(SUBSTRING(info.REV_NO,0,2),'R','0') END DESC) AS PAGE_RANK , DENSE_RANK() OVER (PARTITION BY info.DOCUMENT_NO, info.REV_NO ORDER BY info.DOCUMENT_NO, CASE WHEN LENGTH(info.REV_NO)=1 THEN info.REV_NO||'Z' ELSE info.REV_NO END DESC, combo.SEQ DESC, info.INTERFACE_DT DESC) AS SEQ_RANK FROM ( SELECT document.* , fileInfo.FILE_NO AS FILENO , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.ORG_FILE_NM , fileInfo.FILE_NM , fileInfo.FILE_PATH_NM , COALESCE(fileInfo.FILE_SIZE, '0') AS fileSize , fileInfo.DISTRIBUTE_TYPE_CD AS distributeTypeCd FROM DOCS_DOCUMENT document , DOCS_DOCUMENT_FILE fileInfo WHERE 1=1 AND document.OBJECT_ID = fileInfo.OBJECT_ID AND DOCUMENT_NO IN (
#{info.objectNo}
) AND COALESCE(VALID_TYPE,'Y') != 'N' ) info , DOCS_COMBO combo WHERE info.distributeTypeCd = combo.VALUE AND combo.COMBO_CD = 'distributeTypeCd' ) WHERE PAGE_RANK = 1 AND SEQ_RANK = 1 ORDER BY DOCUMENT_NO, REV_NO DESC, FILENO

SELECT OBJECT_ID , BUSINESS_AREA_CD , BUSINESS_TYPE_CD , DOC_CLASS_CD1 AS objectClassCd1 , DOC_CLASS_CD2 AS objectClassCd2 , PRODUCT_CD , ECN_NO , ECN_INSERT_UID , DOCUMENT_NO AS objectNo , REV_NO , DOCUMENT_NM AS objectNm , ACCOUNT_NM , STATUS_CD , TOTAL_SHEET , PROJECT_CD , PROJECT_NM , distributeTypeCd , STD_GAPP_DT AS stdGappDt , CHANGE_GAPP_DT AS changeGappDt , SECURITY_TYPE_CD , PROTECT_YN , DESCRIPTION , INSERT_DEPT_NM , INSERT_UID , INSERT_DT , UPDATE_DEPT_NM , UPDATE_UID , UPDATE_DT , INTERFACE_DT AS interfaceDt , FILENO , fileViewNm , ORG_FILE_NM , FILE_NM , FILE_PATH_NM , fileSize , 'Y' AS inspectionYn FROM ( SELECT info.* , DENSE_RANK() OVER (PARTITION BY info.DOCUMENT_NO ORDER BY info.DOCUMENT_NO, CASE WHEN LENGTH(info.REV_NO)=1 THEN info.REV_NO||'Z' ELSE REGEXP_REPLACE(SUBSTRING(info.REV_NO,0,2),'R','0') END DESC) AS PAGE_RANK , DENSE_RANK() OVER (PARTITION BY info.DOCUMENT_NO, info.REV_NO ORDER BY info.DOCUMENT_NO, CASE WHEN LENGTH(info.REV_NO)=1 THEN info.REV_NO||'Z' ELSE info.REV_NO END DESC, combo.SEQ DESC, info.INTERFACE_DT DESC) AS SEQ_RANK FROM ( SELECT document.* , fileInfo.FILE_NO AS FILENO , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.ORG_FILE_NM , fileInfo.FILE_NM , fileInfo.FILE_PATH_NM , COALESCE(fileInfo.FILE_SIZE, '0') AS fileSize , fileInfo.DISTRIBUTE_TYPE_CD AS distributeTypeCd FROM DOCS_DOCUMENT document , DOCS_DOCUMENT_FILE fileInfo WHERE 1=1 AND document.OBJECT_ID = fileInfo.OBJECT_ID AND (
DOCUMENT_NO LIKE '%' || #{info.objectNo} || '%'
) AND COALESCE(VALID_TYPE,'Y') != 'N' ) info , DOCS_COMBO combo WHERE info.distributeTypeCd = combo.VALUE AND combo.COMBO_CD = 'distributeTypeCd' ) WHERE PAGE_RANK = 1 AND SEQ_RANK = 1 ORDER BY DOCUMENT_NO, REV_NO DESC, FILENO

SELECT OBJECT_ID , BUSINESS_AREA_CD , BUSINESS_TYPE_CD , ECN_NO , ECN_INSERT_UID , DRAWING_TYPE , DRAWING_NO AS objectNo , DRAWING_REV , REV_NO , DRAWING_NM AS objectNm , DISTRIBUTE_TYPE_CD , STATUS_CD , CURRENT_PAGE_NO , TOTAL_PAGE_NO , EFFECTIVE_DT , FILE_PATH_NM , ORG_FILE_NM AS fileViewNm , ORG_FILE_NM , FILE_NM , FILE_SIZE , 1 AS fileNo , '' AS checkSum , STD_GAPP_DT AS stdGappDt , CHANGE_GAPP_DT AS changeGappDt , PURCHASER_UID , VENDOR_CD , DESCRIPTION , SECURITY_TYPE_CD , PROTECT_YN , INSERT_DEPT_NM , INSERT_UID , INSERT_DT , UPDATE_DEPT_NM , UPDATE_UID , UPDATE_DT , INTERFACE_DT AS interfaceDt , PRODUCT_CD , PLANT_CD , 'Y' AS inspectionYn FROM ( SELECT drawing.* , DENSE_RANK() OVER (PARTITION BY drawing.DRAWING_NO, drawing.CURRENT_PAGE_NO ORDER BY drawing.DRAWING_NO, CASE WHEN REGEXP_INSTR(drawing.REV_NO,'[^0-9]') = 0 THEN drawing.REV_NO ELSE CASE WHEN LENGTH(drawing.REV_NO)=1 THEN drawing.REV_NO||'Z' ELSE drawing.REV_NO END END DESC, drawing.CURRENT_PAGE_NO) AS PAGE_RANK , DENSE_RANK() OVER (PARTITION BY drawing.DRAWING_NO, drawing.DRAWING_REV, drawing.CURRENT_PAGE_NO ORDER BY drawing.DRAWING_NO, CASE WHEN REGEXP_INSTR(drawing.REV_NO,'[^0-9]') = 0 THEN drawing.REV_NO ELSE CASE WHEN LENGTH(drawing.REV_NO)=1 THEN drawing.REV_NO||'Z' ELSE drawing.REV_NO END END DESC, drawing.CURRENT_PAGE_NO, combo.SEQ DESC, drawing.INTERFACE_DT DESC) AS SEQ_RANK FROM DOCS_DRAWING drawing , DOCS_COMBO combo WHERE combo.COMBO_CD = 'distributeTypeCd' AND drawing.DRAWING_NO IN (
#{info.objectNo}
) AND COALESCE(drawing.VALID_TYPE,'Y') != 'N' ) WHERE PAGE_RANK = 1 AND SEQ_RANK = 1 ORDER BY DRAWING_NO, CURRENT_PAGE_NO

SELECT OBJECT_ID , BUSINESS_AREA_CD , BUSINESS_TYPE_CD , ECN_NO , ECN_INSERT_UID , DRAWING_TYPE , DRAWING_NO AS objectNo , DRAWING_REV , REV_NO , DRAWING_NM AS objectNm , DISTRIBUTE_TYPE_CD , STATUS_CD , CURRENT_PAGE_NO , TOTAL_PAGE_NO , EFFECTIVE_DT , FILE_PATH_NM , ORG_FILE_NM AS fileViewNm , ORG_FILE_NM , FILE_NM , FILE_SIZE , 1 AS fileNo , '' AS checkSum , STD_GAPP_DT AS stdGappDt , CHANGE_GAPP_DT AS changeGappDt , PURCHASER_UID , VENDOR_CD , DESCRIPTION , SECURITY_TYPE_CD , PROTECT_YN , INSERT_DEPT_NM , INSERT_UID , INSERT_DT , UPDATE_DEPT_NM , UPDATE_UID , UPDATE_DT , INTERFACE_DT AS interfaceDt , PRODUCT_CD , PLANT_CD , 'Y' AS inspectionYn FROM ( SELECT drawing.* , DENSE_RANK() OVER (PARTITION BY drawing.DRAWING_NO, drawing.CURRENT_PAGE_NO ORDER BY drawing.DRAWING_NO, CASE WHEN REGEXP_INSTR(drawing.REV_NO,'[^0-9]') = 0 THEN drawing.REV_NO ELSE CASE WHEN LENGTH(drawing.REV_NO)=1 THEN drawing.REV_NO||'Z' ELSE drawing.REV_NO END END DESC, drawing.CURRENT_PAGE_NO) AS PAGE_RANK , DENSE_RANK() OVER (PARTITION BY drawing.DRAWING_NO, drawing.DRAWING_REV, drawing.CURRENT_PAGE_NO ORDER BY drawing.DRAWING_NO, CASE WHEN REGEXP_INSTR(drawing.REV_NO,'[^0-9]') = 0 THEN drawing.REV_NO ELSE CASE WHEN LENGTH(drawing.REV_NO)=1 THEN drawing.REV_NO||'Z' ELSE drawing.REV_NO END END DESC, drawing.CURRENT_PAGE_NO, combo.SEQ DESC, drawing.INTERFACE_DT DESC) AS SEQ_RANK FROM DOCS_DRAWING drawing , DOCS_COMBO combo WHERE combo.COMBO_CD = 'distributeTypeCd' AND (
drawing.DRAWING_NO LIKE '%' || #{info.objectNo} || '%'
) AND COALESCE(drawing.VALID_TYPE,'Y') != 'N' ) WHERE PAGE_RANK = 1 AND SEQ_RANK = 1 ORDER BY DRAWING_NO, CURRENT_PAGE_NO

SELECT OBJECT_ID , BUSINESS_AREA_CD , BUSINESS_TYPE_CD , SW_CLASS_CD1 AS objectClassCd1 , SW_CLASS_CD2 AS objectClassCd2 , SW_TYPE_CD , PRODUCT_CD , ECN_NO , ECN_INSERT_UID , SW_NO AS objectNo , DISTRIBUTE_TYPE_CD , REV_NO , SW_NM AS objectNm , STATUS_CD , SW_VERSION_NO , DOC_VERSION_NO , PROJECT_CD , PROJECT_NM , STD_GAPP_DT AS stdGappDt , CHANGE_GAPP_DT AS changeGappDt , DESCRIPTION , SECURITY_TYPE_CD , PROTECT_YN , INSERT_DEPT_NM , INSERT_UID , INSERT_DT , UPDATE_DEPT_NM , UPDATE_UID , UPDATE_DT , INTERFACE_DT AS interfaceDt , FILE_NO , fileViewNm , ORG_FILE_NM , FILE_NM , FILE_PATH_NM , CHECK_SUM , distributeTypeCd , fileSize , 'Y' AS inspectionYn FROM ( SELECT info.* , DENSE_RANK() OVER (PARTITION BY info.SW_NO ORDER BY info.SW_NO, CASE WHEN LENGTH(info.REV_NO)=1 THEN info.REV_NO||'Z' ELSE info.REV_NO END DESC) AS PAGE_RANK , DENSE_RANK() OVER (PARTITION BY info.SW_NO, info.REV_NO ORDER BY info.SW_NO, CASE WHEN LENGTH(info.REV_NO)=1 THEN info.REV_NO||'Z' ELSE info.REV_NO END DESC, combo.SEQ DESC, info.INTERFACE_DT DESC) AS SEQ_RANK FROM ( SELECT sw.* , fileInfo.FILE_NO , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.ORG_FILE_NM , fileInfo.FILE_NM , fileInfo.FILE_PATH_NM , fileInfo.CHECK_SUM , fileInfo.DISTRIBUTE_TYPE_CD AS distributeTypeCd , COALESCE(fileInfo.FILE_SIZE, '0') AS fileSize FROM DOCS_SW sw , DOCS_SW_FILE fileInfo WHERE 1=1 AND sw.OBJECT_ID = fileInfo.OBJECT_ID AND SW_NO IN (
#{info.objectNo}
) AND COALESCE(VALID_TYPE,'Y') != 'N' ) info , DOCS_COMBO combo WHERE info.distributeTypeCd = combo.VALUE AND combo.COMBO_CD = 'distributeTypeCd' ) WHERE PAGE_RANK = 1 AND SEQ_RANK = 1 ORDER BY SW_NO, REV_NO DESC, FILE_NO

SELECT OBJECT_ID , BUSINESS_AREA_CD , BUSINESS_TYPE_CD , SW_CLASS_CD1 AS objectClassCd1 , SW_CLASS_CD2 AS objectClassCd2 , SW_TYPE_CD , PRODUCT_CD , ECN_NO , ECN_INSERT_UID , SW_NO AS objectNo , DISTRIBUTE_TYPE_CD , REV_NO , SW_NM AS objectNm , STATUS_CD , SW_VERSION_NO , DOC_VERSION_NO , PROJECT_CD , PROJECT_NM , STD_GAPP_DT AS stdGappDt , CHANGE_GAPP_DT AS changeGappDt , DESCRIPTION , SECURITY_TYPE_CD , PROTECT_YN , INSERT_DEPT_NM , INSERT_UID , INSERT_DT , UPDATE_DEPT_NM , UPDATE_UID , UPDATE_DT , INTERFACE_DT AS interfaceDt , FILE_NO , fileViewNm , ORG_FILE_NM , FILE_NM , FILE_PATH_NM , CHECK_SUM , distributeTypeCd , fileSize , 'Y' AS inspectionYn FROM ( SELECT info.* , DENSE_RANK() OVER (PARTITION BY info.SW_NO ORDER BY info.SW_NO, CASE WHEN LENGTH(info.REV_NO)=1 THEN info.REV_NO||'Z' ELSE info.REV_NO END DESC) AS PAGE_RANK , DENSE_RANK() OVER (PARTITION BY info.SW_NO, info.REV_NO ORDER BY info.SW_NO, CASE WHEN LENGTH(info.REV_NO)=1 THEN info.REV_NO||'Z' ELSE info.REV_NO END DESC, combo.SEQ DESC, info.INTERFACE_DT DESC) AS SEQ_RANK FROM ( SELECT sw.* , fileInfo.FILE_NO , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.ORG_FILE_NM , fileInfo.FILE_NM , fileInfo.FILE_PATH_NM , fileInfo.CHECK_SUM , fileInfo.DISTRIBUTE_TYPE_CD AS distributeTypeCd , COALESCE(fileInfo.FILE_SIZE, '0') AS fileSize FROM DOCS_SW sw , DOCS_SW_FILE fileInfo WHERE 1=1 AND sw.OBJECT_ID = fileInfo.OBJECT_ID AND (
sw.SW_NO LIKE '%' || #{info.objectNo} || '%'
) AND COALESCE(VALID_TYPE,'Y') != 'N' ) info , DOCS_COMBO combo WHERE info.distributeTypeCd = combo.VALUE AND combo.COMBO_CD = 'distributeTypeCd' ) WHERE PAGE_RANK = 1 AND SEQ_RANK = 1 ORDER BY SW_NO, REV_NO DESC, FILE_NO

SELECT info.* , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.ORG_FILE_NM , fileInfo.FILE_NM , fileInfo.FILE_SIZE , fileInfo.FILE_PATH_NM , fileInfo.FILE_NO AS fileNo FROM ( SELECT info.* FROM ( SELECT 'Y' AS inspectionYn , product.OBJECT_ID , product.BUSINESS_AREA_CD , product.BUSINESS_TYPE_CD , product.DOC_CLASS_CD1 AS objectClassCd1 , product.DOC_CLASS_NM1 AS objectClassNm1 , product.DOC_CLASS_CD2 AS objectClassCd2 , product.DOC_CLASS_NM2 AS objectClassNm2 , product.DRAWING_NO AS objectNo , product.REV_NO , product.DOCUMENT_NM AS objectNm , product.STATUS_CD , product.TOTAL_PAGE_CNT , product.SECURITY_TYPE_CD , product.APPLY_PRODUCT_NO , product.APPLY_HOGI_NO , product.CALL_ID , product.ECN_NO , product.PROCESS_TYPE_CD , product.DESCRIPTION , product.INSERT_DEPT_NM , product.INSERT_UID , product.INSERT_DT , product.UPDATE_DEPT_NM , product.UPDATE_UID , product.UPDATE_DT , product.INTERFACE_DT AS interfaceDt FROM DOCS_PRODUCT_DOCUMENT product WHERE 1=1 AND DRAWING_NO IN (
#{info.objectNo}
) ORDER BY REV_NO DESC ) info ) info INNER JOIN DOCS_PRODUCT_DOCUMENT_FILE fileInfo ON info.OBJECT_ID = fileInfo.OBJECT_ID

SELECT info.* , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.ORG_FILE_NM , fileInfo.FILE_NM , fileInfo.FILE_SIZE , fileInfo.FILE_PATH_NM , CAST(fileInfo.FILE_NO AS INTEGER) AS fileNo FROM ( SELECT info.* FROM ( SELECT 'Y' AS inspectionYn , product.OBJECT_ID , product.BUSINESS_AREA_CD , product.BUSINESS_TYPE_CD , product.DOC_CLASS_CD1 AS objectClassCd1 , product.DOC_CLASS_NM1 AS objectClassNm1 , product.DOC_CLASS_CD2 AS objectClassCd2 , product.DOC_CLASS_NM2 AS objectClassNm2 , product.DRAWING_NO AS objectNo , product.REV_NO , product.DOCUMENT_NM AS objectNm , product.STATUS_CD , product.TOTAL_PAGE_CNT , product.SECURITY_TYPE_CD , product.APPLY_PRODUCT_NO , product.APPLY_HOGI_NO , product.CALL_ID , product.ECN_NO , product.PROCESS_TYPE_CD , product.DESCRIPTION , product.INSERT_DEPT_NM , product.INSERT_UID , product.INSERT_DT , product.UPDATE_DEPT_NM , product.UPDATE_UID , product.UPDATE_DT , product.INTERFACE_DT AS interfaceDt FROM DOCS_PRODUCT_DOCUMENT product WHERE 1=1 AND (
product.DRAWING_NO LIKE '%' || #{info.objectNo} || '%'
) ORDER BY REV_NO DESC ) info ) info INNER JOIN DOCS_PRODUCT_DOCUMENT_FILE fileInfo ON info.OBJECT_ID = fileInfo.OBJECT_ID

SELECT info.* , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.ORG_FILE_NM , fileInfo.FILE_NM , fileInfo.FILE_SIZE , fileInfo.FILE_PATH_NM , fileInfo.FILE_NO AS fileNo FROM ( SELECT info.* FROM ( SELECT 'Y' AS inspectionYn , product.OBJECT_ID , product.BUSINESS_AREA_CD , product.BUSINESS_TYPE_CD , product.ECN_NO , product.PRODUCT_NO , product.SW_CLASS_CD1 AS objectClassCd1 , product.SW_CLASS_NM1 AS objectClassNm1 , product.SW_CLASS_CD2 AS objectClassCd2 , product.SW_CLASS_NM2 AS objectClassNm2 , product.SW_NO AS objectNo , product.SW_VERSION_NO , product.SW_NM AS objectNm , product.REV_NO , product.STATUS_CD , product.DESCRIPTION , product.SECURITY_TYPE_CD , product.INSERT_DEPT_NM , product.INSERT_UID , product.INSERT_DT , product.UPDATE_DEPT_NM , product.UPDATE_UID , product.UPDATE_DT , fileInfo.ORG_FILE_NM AS fileNm , fileInfo.FILE_NO , product.INTERFACE_DT AS interfaceDt FROM DOCS_PRODUCT_SW product INNER JOIN DOCS_PRODUCT_SW_FILE fileInfo ON product.OBJECT_ID = fileInfo.OBJECT_ID WHERE 1=1 AND SW_NO IN (
#{info.objectNo}
) ORDER BY REV_NO DESC ) info ) info INNER JOIN DOCS_PRODUCT_SW_FILE fileInfo ON info.OBJECT_ID = fileInfo.OBJECT_ID

SELECT info.* , fileInfo.ORG_FILE_NM AS fileViewNm , fileInfo.ORG_FILE_NM , fileInfo.FILE_NM , fileInfo.FILE_SIZE , fileInfo.FILE_PATH_NM , fileInfo.FILE_NO AS fileNo FROM ( SELECT info.* FROM ( SELECT 'Y' AS inspectionYn , product.OBJECT_ID , product.BUSINESS_AREA_CD , product.BUSINESS_TYPE_CD , product.ECN_NO , product.PRODUCT_NO , product.SW_CLASS_CD1 AS objectClassCd1 , product.SW_CLASS_NM1 AS objectClassNm1 , product.SW_CLASS_CD2 AS objectClassCd2 , product.SW_CLASS_NM2 AS objectClassNm2 , product.SW_NO AS objectNo , product.SW_VERSION_NO , product.SW_NM AS objectNm , product.REV_NO , product.STATUS_CD , product.DESCRIPTION , product.SECURITY_TYPE_CD , product.INSERT_DEPT_NM , product.INSERT_UID , product.INSERT_DT , product.UPDATE_DEPT_NM , product.UPDATE_UID , product.UPDATE_DT , fileInfo.ORG_FILE_NM AS fileNm , fileInfo.FILE_NO , product.INTERFACE_DT AS interfaceDt FROM DOCS_PRODUCT_SW product INNER JOIN DOCS_PRODUCT_SW_FILE fileInfo ON product.OBJECT_ID = fileInfo.OBJECT_ID WHERE 1=1 AND (
product.SW_NO LIKE '%' || #{info.objectNo} || '%'
) ORDER BY REV_NO DESC ) info ) info INNER JOIN DOCS_PRODUCT_SW_FILE fileInfo ON info.OBJECT_ID = fileInfo.OBJECT_ID

mapper.update:
